// n8n provides the input items in the '$input' variable
const items = $input.all();
const targetPrefix = "Scale Virtually: VA Candidates for ";

const cleanedItems = items.map(item => {
  // Access the 'Subject' inside the json property of the n8n item
  let subject = item.json.Subject || "";

  // Regex to strip "Re:", "Fwd:", and the specific "Scale Virtually" prefix
  const regex = new RegExp(`^(Re: |Fwd: )*${targetPrefix}`, "i");

  const newSubject = subject.replace(regex, "").trim();

  // Return the n8n item structure: { json: { ... } }
  return {
    json: {
      ...item.json,
      Subject: newSubject
    }
  };
});

return cleanedItems;

// Get the current date and time in PHT (Philippine Time)
const now = new Date();
const options = { 
  month: 'short', 
  day: '2-digit', 
  year: 'numeric', 
  hour: '2-digit', 
  minute: '2-digit', 
  hour12: true, 
  timeZone: 'Asia/Manila' 
};

// Format: Feb 06, 2026 11:45 PM PHT
const timestamp = now.toLocaleString('en-US', options).replace(',', '') + ' PHT';

const items = $input.all();

return items.map(item => {
  const existingUpdates = item.json["PR – Updates"] || "";

  // 1. Try to extract from the root-level "output" field first
  let newSummary = item.json["output"] || "";

  // 2. Fallback: If "output" is empty, look deep inside the Gemini "candidates" array
  if (!newSummary.trim()) {
    try {
      if (
        item.json.candidates && 
        item.json.candidates[0] && 
        item.json.candidates[0].content && 
        item.json.candidates[0].content.parts && 
        item.json.candidates[0].content.parts[0]
      ) {
        newSummary = item.json.candidates[0].content.parts[0].text || "";
      }
    } catch (e) {
      newSummary = "";
    }
  }

  // Safeguard: If no update summary was found in either location, return the original record unchanged
  if (!newSummary.trim()) {
    return {
      json: {
        ...item.json,
        final_update_string: existingUpdates
      }
    };
  }

  // Create the new bullet entry
  const newEntry = `• [${timestamp}] ${newSummary.trim()}`;

  // APPEND to the end: existing + new
  // If the existing field is empty, just use the new entry; otherwise, append it with newlines
  const updatedField = existingUpdates 
    ? `${existingUpdates.trim()}\n\n${newEntry}` 
    : newEntry;

  return {
    json: {
      ...item.json,
      final_update_string: updatedField
    }
  };
});

